prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?flow ?sourceName ?targetName ?flowName WHERE {
  ?flow a bbo:SequenceFlow .
  ?flow tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_e0cff846_e631_4657_9d55_ab4c98968cd7> .
  ?flow bbo:has_sourceRef ?source .
  ?flow bbo:has_targetRef ?target .
  OPTIONAL { ?source bbo:name ?sourceName . }
  OPTIONAL { ?target bbo:name ?targetName . }
  OPTIONAL { ?flow bbo:name ?flowName . }
}
ORDER BY ?sourceName
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?gatewayName ?direction ?default WHERE {
  ?gateway a bboExt:ExclusiveGateway .
  ?gateway tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_e0cff846_e631_4657_9d55_ab4c98968cd7> .
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?direction . }
  OPTIONAL { ?gateway bboExt:default ?default . }
}
